commit 83a59701cd4933722ca5259fb63d8bb68b0ecd67
Author: Jiri Kraus <jkraus@nvidia.com>
Date:   Mon Mar 4 11:21:32 2024 +0100

    Added MPI_Barrier after MPI_Bcast to make NCCL initi more robust.
---
 nccl/jacobi.cpp         | 3 +++
 nccl_graphs/jacobi.cpp  | 3 +++
 nccl_overlap/jacobi.cpp | 3 +++
 3 files changed, 9 insertions(+)

diff --git a/nccl/jacobi.cpp b/nccl/jacobi.cpp
index 405844c..5c94b87 100644
--- a/nccl/jacobi.cpp
+++ b/nccl/jacobi.cpp
@@ -167,6 +167,9 @@ int main(int argc, char* argv[]) {
     ncclUniqueId nccl_uid;
     if (rank == 0) NCCL_CALL(ncclGetUniqueId(&nccl_uid));
     MPI_CALL(MPI_Bcast(&nccl_uid, sizeof(ncclUniqueId), MPI_BYTE, 0, MPI_COMM_WORLD));
+    // MPI_Barrier ensures that all processs have completed the MPI_Bcast.
+    // This can be required when combining MPI with other communication libraries like NCCL.
+    MPI_CALL(MPI_Barrier(MPI_COMM_WORLD));

     const int iter_max = get_argval<int>(argv, argv + argc, "-niter", 1000);
     const int nccheck = get_argval<int>(argv, argv + argc, "-nccheck", 1);
diff --git a/nccl_graphs/jacobi.cpp b/nccl_graphs/jacobi.cpp
index 00c986a..89a9325 100644
