+++ b/nccl_graphs/jacobi.cpp
@@ -167,6 +167,9 @@ int main(int argc, char* argv[]) {
     ncclUniqueId nccl_uid;
     if (rank == 0) NCCL_CALL(ncclGetUniqueId(&nccl_uid));
     MPI_CALL(MPI_Bcast(&nccl_uid, sizeof(ncclUniqueId), MPI_BYTE, 0, MPI_COMM_WORLD));
+    // MPI_Barrier ensures that all processs have completed the MPI_Bcast.
+    // This can be required when combining MPI with other communication libraries like NCCL.
+    MPI_CALL(MPI_Barrier(MPI_COMM_WORLD));

     const int iter_max = get_argval<int>(argv, argv + argc, "-niter", 1000);
     const int nccheck = get_argval<int>(argv, argv + argc, "-nccheck", 1);
diff --git a/nccl_overlap/jacobi.cpp b/nccl_overlap/jacobi.cpp
index 408f9dd..14a8ef3 100644
--- a/nccl_overlap/jacobi.cpp
+++ b/nccl_overlap/jacobi.cpp
@@ -167,6 +167,9 @@ int main(int argc, char* argv[]) {
     ncclUniqueId nccl_uid;
     if (rank == 0) NCCL_CALL(ncclGetUniqueId(&nccl_uid));
     MPI_CALL(MPI_Bcast(&nccl_uid, sizeof(ncclUniqueId), MPI_BYTE, 0, MPI_COMM_WORLD));
+    // MPI_Barrier ensures that all processs have completed the MPI_Bcast.
+    // This can be required when combining MPI with other communication libraries like NCCL.
+    MPI_CALL(MPI_Barrier(MPI_COMM_WORLD));

     const int iter_max = get_argval<int>(argv, argv + argc, "-niter", 1000);
     const int nccheck = get_argval<int>(argv, argv + argc, "-nccheck", 1);

commit f90a770fb54969020e8a506c1465698b74ecd394
Author: Jiri Kraus <jkraus@nvidia.com>
Date:   Mon Oct 17 14:23:03 2022 +0200

    Improved device affinity handling

    to allow using CUDA_VISIBLE_DEVICES to handle device affinity.
---
 nccl_graphs/jacobi.cpp | 17 ++++++++++++++++-
 1 file changed, 16 insertions(+), 1 deletion(-)

diff --git a/nccl_graphs/jacobi.cpp b/nccl_graphs/jacobi.cpp
index fac463d..00c986a 100644
--- a/nccl_graphs/jacobi.cpp
+++ b/nccl_graphs/jacobi.cpp
@@ -161,6 +161,8 @@ int main(int argc, char* argv[]) {
     MPI_CALL(MPI_Comm_rank(MPI_COMM_WORLD, &rank));
     int size;
     MPI_CALL(MPI_Comm_size(MPI_COMM_WORLD, &size));
+    int num_devices = 0;
+    CUDA_RT_CALL(cudaGetDeviceCount(&num_devices));

     ncclUniqueId nccl_uid;
     if (rank == 0) NCCL_CALL(ncclGetUniqueId(&nccl_uid));
@@ -173,17 +175,30 @@ int main(int argc, char* argv[]) {
     const bool csv = get_arg(argv, argv + argc, "-csv");

     int local_rank = -1;
+    int local_size = 1;
     {
         MPI_Comm local_comm;
         MPI_CALL(MPI_Comm_split_type(MPI_COMM_WORLD, MPI_COMM_TYPE_SHARED, rank, MPI_INFO_NULL,
                                      &local_comm));

         MPI_CALL(MPI_Comm_rank(local_comm, &local_rank));
+        MPI_CALL(MPI_Comm_size(local_comm, &local_size));

         MPI_CALL(MPI_Comm_free(&local_comm));
     }

-    CUDA_RT_CALL(cudaSetDevice(local_rank));
+    if ( 1 < num_devices && num_devices < local_size )
+    {
+        fprintf(stderr,"ERROR Number of visible devices (%d) is less than number of ranks on the node (%d)!\n", num_devices, local_size);
+        MPI_CALL(MPI_Finalize());
+        return 1;
+    }
+    if ( 1 == num_devices ) {
+        // Only 1 device visbile assuming GPU affinity is handled via CUDA_VISIBLE_DEVICES
+        CUDA_RT_CALL(cudaSetDevice(0));
+    } else {
+        CUDA_RT_CALL(cudaSetDevice(local_rank));
+    }
     CUDA_RT_CALL(cudaFree(0));

     ncclComm_t nccl_comm;

